sys_script_email.script:
(function runMailScript(current, template, email, email_action, event) {
    try {
        // Initialize GlideSysAttachment
        var attachment = new GlideSysAttachment();

        // Get the certificate reference sys_id
        var certificateRef = current.getValue('certificate'); // Ensure 'certificate' is the correct field name

        gs.info("Certificate Sys ID: " + certificateRef);

        if (!certificateRef) {
            gs.info("Certificate reference is empty.");
            return;
        }

        // Retrieve the certificate record using getRefRecord()
        var certRecord = current.certificate.getRefRecord();

        if (!certRecord.isValidRecord()) {
            gs.info("Certificate record not found.");
            return;
        }

        // Get the certificate content and serial number
        var dynamicContent = certRecord.getValue('certificate'); // Replace 'certificate' with the actual field name containing certificate data
        var serialNumber = certRecord.getValue('serial_number'); // Replace 'serial_number' with the actual field name for serial number

        gs.info("Certificate Content: " + dynamicContent);
        gs.info("Serial Number: " + serialNumber);

        if (!dynamicContent) {
            gs.info("Certificate content is empty.");
            return;
        }

        if (!serialNumber) {
            serialNumber = "unknown";
            gs.info("Serial number is empty. Defaulting to 'unknown'.");
        }

        // Create the attachment name with serial number
        var attachmentName = "certificate_" + serialNumber + ".pem";
        gs.info("Attachment Name: " + attachmentName);

        // Write the attachment to the certificate record
        var attachmentSysId = attachment.write(certRecord, attachmentName, "application/x-pem-file", dynamicContent);

        if (attachmentSysId) {
            gs.info("Attachment created successfully with sys_id: " + attachmentSysId);

            // Construct the download URL
            var instanceURL = gs.getProperty('glide.servlet.uri'); // e.g., https://yourinstance.service-now.com/
            var downloadURL = instanceURL + "sys_attachment.do?sys_id=" + attachmentSysId;
            gs.info("Download URL: " + downloadURL);

            // Create the hyperlink
            var hyperlink = '<a href="' + downloadURL + '" style="color: #488EEF; text-decoration: none;">Download Certificate</a>';

            // Append the serial number and hyperlink to the email body
            template.print(hyperlink);
            gs.info("Email body updated with serial number and hyperlink.");
        } else {
            gs.info("Attachment creation failed; no sys_id returned.");
        }
    } catch (e) {
        gs.info("Error during file attachment creation: " + e.message);
    }
})(current, template, email, email_action, event);
